package com.example.biometricauth;

import android.content.Intent;
import android.os.Bundle;
import android.text.TextUtils;
import android.widget.Button;
import android.widget.CheckBox;
import android.widget.EditText;
import android.widget.Toast;

import androidx.appcompat.app.AppCompatActivity;

public class LoginActivity extends AppCompatActivity {

    private EditText etUsername;
    private EditText etPassword;
    private CheckBox cbEnableBiometric;
    private Button btnLogin;
    private Button btnBiometric;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_login);

        etUsername = findViewById(R.id.etUsername);
        etPassword = findViewById(R.id.etPassword);
        cbEnableBiometric = findViewById(R.id.cbEnableBiometric);
        btnLogin = findViewById(R.id.btnLogin);
        btnBiometric = findViewById(R.id.btnBiometric);

        cbEnableBiometric.setChecked(Prefs.isBiometricEnabled(this));
        btnBiometric.setEnabled(Prefs.isBiometricEnabled(this) && BiometricAuthHelper.canAuthenticate(this));

        btnLogin.setOnClickListener(v -> handlePasswordLogin());

        btnBiometric.setOnClickListener(v -> {
            if (!Prefs.isBiometricEnabled(this)) {
                Toast.makeText(this, "Biometric login is not enabled", Toast.LENGTH_SHORT).show();
                return;
            }
            if (!BiometricAuthHelper.canAuthenticate(this)) {
                Toast.makeText(this, "Fingerprint authentication is not available", Toast.LENGTH_SHORT).show();
                return;
            }
            showBiometricPromptAndLogin();
        });

        cbEnableBiometric.setOnCheckedChangeListener((buttonView, isChecked) -> {
            if (isChecked && !BiometricAuthHelper.canAuthenticate(this)) {
                cbEnableBiometric.setChecked(false);
                Toast.makeText(this, "Fingerprint authentication is not available", Toast.LENGTH_SHORT).show();
                return;
            }
            Prefs.setBiometricEnabled(this, isChecked);
            btnBiometric.setEnabled(isChecked && BiometricAuthHelper.canAuthenticate(this));
        });

        if (Prefs.isBiometricEnabled(this) && BiometricAuthHelper.canAuthenticate(this)) {
            showBiometricPromptAndLogin();
        }
    }

    private void handlePasswordLogin() {
        String username = etUsername.getText().toString().trim();
        String password = etPassword.getText().toString().trim();

        if (TextUtils.isEmpty(username)) {
            etUsername.setError("Enter username");
            return;
        }

        if (TextUtils.isEmpty(password)) {
            etPassword.setError("Enter password");
            return;
        }

        if (isValidCredentials(username, password)) {
            Prefs.setAuthenticated(this, true);
            Prefs.setBiometricEnabled(this, cbEnableBiometric.isChecked());
            navigateToHome();
        } else {
            Prefs.clearAuth(this);
            Toast.makeText(this, "Invalid username or password", Toast.LENGTH_SHORT).show();
        }
    }

    private boolean isValidCredentials(String username, String password) {
        return "user".equals(username) && "password".equals(password);
    }

    private void showBiometricPromptAndLogin() {
        BiometricAuthHelper.authenticate(this, "Fingerprint Login", "Use your fingerprint to unlock the app", new BiometricAuthHelper.Callback() {
            @Override
            public void onSuccess() {
                Prefs.setAuthenticated(LoginActivity.this, true);
                navigateToHome();
            }

            @Override
            public void onError(String message) {
                Toast.makeText(LoginActivity.this, message, Toast.LENGTH_SHORT).show();
            }

            @Override
            public void onFailed() {
                Toast.makeText(LoginActivity.this, "Fingerprint not recognized", Toast.LENGTH_SHORT).show();
            }
        });
    }

    private void navigateToHome() {
        Intent intent = new Intent(this, HomeActivity.class);
        startActivity(intent);
        finish();
    }
}

package com.example.biometricauth;

import android.content.Intent;
import android.os.Bundle;
import android.widget.Button;

import androidx.appcompat.app.AppCompatActivity;

public class HomeActivity extends AppCompatActivity {

    private Button btnLogout;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_home);

        btnLogout = findViewById(R.id.btnLogout);
        btnLogout.setOnClickListener(v -> {
            Prefs.clearAuth(this);
            Intent intent = new Intent(this, LoginActivity.class);
            startActivity(intent);
            finish();
        });
    }
}

